+    type F = unsafe extern "C" fn(*mut c_void) -> c_int;
+    let sym = unsafe { libc::dlsym(libc::RTLD_NEXT, c"__gconv_close".as_ptr()) };
+    if sym.is_null() {
+        return -1;
+    }
+    let f: F = unsafe { std::mem::transmute(sym) };
+    unsafe { f(handle) }
+}
