+    assert_eq!(rc, libc::EINVAL);
+}
+
+// ===========================================================================
+// posix_spawn_file_actions_add*
+// ===========================================================================
+
+#[test]
+fn file_actions_addclose() {
+    let mut fa = AlignedBuf::new();
+    unsafe { posix_spawn_file_actions_init(fa.as_mut_ptr().cast()) };
